"""
mkt-original — Proverbs 28–30 (88 verses)
Run: python3 scripts/zc-original-proverbs-28-30.py
Ch28: Torah-law antithesis (vv4,7,9); confession and mercy (v13 — yada'/kasah);
  fear vs hard heart (v14); integrity saves (v18); trust own heart = fool (v26).
Ch29: Stiff neck before ruin (v1); righteous rule (v2); hazon-vision (v18);
  kābôd/rûaḥ humility (v23); fear of man vs YHWH-trust (v25).
Ch30: Agur's non-Israelite oracle; epistemological humility (vv1-4); &#8220;what
  is his name and his son's name?&#8221; (v4 — Christological resonance); &#8216;every
  word of God proves true&#8217; (v5); prayer for neither poverty nor riches (vv8-9);
  generational portrait (vv11-14); numerical wisdom sayings.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

PROVERBS = {
  "28": {
    "1": "<p><em>Nāsû rĕšāʿîm wĕ'ên rōdēp</em> = &#8220;The wicked flee when no one pursues&#8221; — the guilty conscience creates its own pursuers. <em>Wĕṣaddîqîm kikpîr yibṭāḥ</em> = &#8220;but the righteous are as bold as a young lion.&#8221; <em>Kĕpîr</em> = a young, full-grown lion at peak strength — the image is not of aggression but of confidence: the righteous person does not bolt because there is nothing to flee from. Moral innocence and YHWH-trust together produce this unshakable bearing.</p>",
    "2": "<p><em>Bĕpeša' ʾereṣ rabbîm śārêhā</em> = &#8220;In the transgression of a land many are its rulers&#8221; — national sin fragments political authority; too many competing rulers is itself a symptom of moral disorder. <em>Wĕbĕ'ādām mêbîn yōdēaʿ</em> — disputed: <em>yādaʿ</em> (H3045, dispute_level=2) with the range &#8220;know / understand / perceive / experience.&#8221; The MKT renders &#8220;through a man of understanding and knowledge its stability endures&#8221; — one person of discernment can stabilize what collective sin has shattered.</p>",
    "3": "<p><em>Geber-rāš wĕ'ōšēq dallîm</em> = &#8220;A poor man who oppresses the poor&#8221; — the inversion is the point: the one with no resources to oppress still does so. <em>Māṭār sōḥēp wĕ'ên lāḥem</em> = &#8220;like a driving/sweeping rain that leaves no food&#8221; — the heavy rains that strip the soil and wash away crops rather than watering them. The rain is violent, not nourishing: destructive without remedy.</p>",
    "4": "<p><em>ʿŌzĕbê tôrāh yĕhallĕlû rāšāʿ</em> = &#8220;Those who forsake the law (<em>tôrāh</em>) praise the wicked&#8221; — <em>tôrāh</em> is instruction/law, the foundational term for divine teaching. Those who abandon it lose the moral framework that enables them to identify wickedness as wicked; they end up praising it instead. <em>Wĕšōmĕrê tôrāh yitgārû bām</em> = &#8220;but those who keep the law contend with them&#8221; — law-keepers resist the wicked by definition.</p>",
    "5": "<p><em>ʾAnšê-rāʿ lō' yābînû mišpāṭ</em> = &#8220;Evil men do not understand justice&#8221; — moral failing produces epistemic incapacity; the wicked cannot perceive right order because wickedness deforms the perceiving faculty. <em>Wĕmĕbaqqĕšê YHWH yābînû kōl</em> = &#8220;but those who seek YHWH understand everything.&#8221; YHWH (H3068, dispute_level=4) — the personal divine name; &#8220;LORD&#8221; in standard translations conceals this. Seeking YHWH is the comprehensive epistemological orientation that opens the full range of understanding.</p>",
    "6": "<p>'Better is the poor man who walks in his integrity (<em>bĕtummô</em>) than the one who is perverse in his ways (<em>wĕ'iqqēš dĕrākayim</em>), even if he is rich' — <em>tōm</em> (integrity, wholeness) is the inner coherence of the person whose conduct matches their values. <em>ʾIqqēš</em> (crooked/twisted) is the antonym: a person whose paths are doubled/divided — saying one thing, doing another. The verse weighs character against wealth and finds wealth lacking.</p>",
    "7": "<p><em>Nôṣēr tôrāh bēn mêbîn</em> = &#8220;Whoever keeps the law is a wise son&#8221; — <em>nāṣar</em> (keep/guard/watch) — the watchful guarding of the <em>tôrāh</em>. <em>Wĕrōʿēh zôlĕlîm yaklîm ʾābîw</em> = &#8220;but a companion of gluttons (<em>zôlĕlîm</em>) brings shame on his father&#8221; — <em>zālal</em> (be loose/worthless/prodigal) encompasses both excess eating and moral looseness; the gluttonous companion is the fool-company warning of 13:20.</p>",
    "8": "<p><em>Marbeh hônô bĕneśek ûbĕtarbît</em> = &#8220;Whoever increases wealth by interest (<em>neśek</em>) and dishonest gain&#8221; — <em>neśek</em> (bite, interest on a loan) and <em>tarbît</em> (increase/usury) are the twin commercial vices forbidden in the Torah (Lev 25:36-37). <em>Lĕḥônen dallîm yiqbĕṣennû</em> = &#8220;gathers it for one who will be generous to the poor&#8221; — divine irony: the ill-gotten wealth is providentially redirected to the generous. YHWH ultimately controls the redistribution of wealth.</p>",
    "9": "<p><em>Mēsîr ʾoznô miššĕmōaʿ tôrāh</em> = &#8220;Whoever turns his ear away from hearing the law&#8221; — the deliberate aversion of the ear from <em>tôrāh</em>. <em>Gam-tĕpillātô tôʿēbāh</em> = &#8220;even his prayer is detestable&#8221; (<em>tôʿēbāh</em>, abomination). The shocking inversion: the person who ignores divine instruction when it suits them cannot expect their requests to be received. Selective listening to God is answered by selective hearing of prayer.</p>",
    "10": "<p><em>Mašgeh yĕšārîm bĕderek rāʿ</em> = &#8220;Whoever leads the righteous astray in an evil way&#8221; — <em>šāgāh</em> (lead astray, cause to wander) describes deliberate misdirection of those who are upright. <em>Bišḥûtô hûʾ-yippôl</em> = &#8220;into his own pit he will fall&#8221; — the trap prepared for others becomes the agent's own snare. <em>Ûtĕmîmîm yinḥălû-ṭôb</em> = &#8220;but the blameless will inherit good.&#8221;</p>",
    "11": "<p><em>Ḥākām bĕ'ênāyw ʾîš ʿāšîr</em> = &#8220;A rich man is wise in his own eyes&#8221; — wealth creates the illusion of wisdom by providing access to results (people comply, projects succeed) that real wisdom would also produce. <em>Wĕdal mêbîn yaḥqĕrennû</em> = &#8220;but a poor man with discernment will see right through him.&#8221; <em>Ḥāqar</em> (search/investigate/probe) — the discerning poor person probes and exposes the hollow wisdom of the wealthy fool.</p>",
    "12": "<p><em>Baʿălôṣ ṣaddîqîm rabbāh tipʾāret</em> = &#8220;When the righteous triumph, great is the glory/rejoicing&#8221; — <em>tipʾāret</em> (glory/beauty/splendor) describes the flourishing state of a community under righteous leadership. <em>Ûbĕqûm rĕšāʿîm yĕḥuppas ʾādām</em> = &#8220;but when the wicked rise to power, people go into hiding&#8221; — the social compression of wickedness in power: public life becomes dangerous, people withdraw. See v28 for the mirror image.</p>",
    "13": "<p><em>Mĕkasseh pĕšāʿāyw lō' yaṣlîaḥ</em> = &#8220;Whoever conceals his sins will not prosper&#8221; — <em>kāsāh</em> (cover/conceal) here is self-protective hiding, not the generous &#8220;covering&#8221; of 17:9. Self-concealment of sin prevents the breakthrough that would lead to mercy. <em>Ûmôdeh wĕ'ōzēb yĕruḥām</em> = &#8220;but whoever confesses (<em>yādāh</em>) and forsakes them will find mercy.&#8221; <em>Yādāh</em> (confess/praise) is the same root as thanksgiving: confession is a kind of honoring of God's authority over the sin. The closest wisdom equivalent to the NT confession theology of 1 John 1:9.</p>",
    "14": "<p><em>ʾAšrê ʾādām mĕpahēd tāmîd</em> = &#8220;Happy is the one who fears (<em>pāḥad</em>) the LORD continually&#8221; — <em>pāḥad</em> is the strong trembling-fear, more vivid than <em>yārēʾ</em> (the standard &#8220;fear of YHWH&#8221;); it suggests an ongoing disposition of awe before YHWH's holiness. <em>Ûmaqšeh libbô yippōl bĕrāʿāh</em> = &#8220;but whoever hardens his heart (<em>qāšāh-lēb</em>) will fall into calamity.&#8221; The hard heart is Pharaoh's condition (Exod 7:3); applying it to the wisdom setting grounds the two trajectories of Proverbs in covenantal history.</p>",
    "15": "<p><em>ʾAryēh nōhēm wĕdōb šōqēq</em> = &#8220;A roaring lion or a charging/rushing bear (<em>dōb šōqēq</em>)&#8221; — <em>šāqaq</em> (rush headlong, roam recklessly) describes the bear's predatory charging motion. <em>Mōšēl rāšāʿ ʿal-ʿam dāl</em> = &#8220;so is a wicked ruler over a poor people&#8221; — the wicked ruler over the powerless combines both predatory animals: the lion's roar (intimidation) and the bear's charge (violence). The poor people have no means of resistance.</p>",
    "16": "<p><em>Nāgîd ḥăsar tĕbûnôt</em> = &#8220;A ruler lacking discernment (<em>tĕbûnôt</em>)&#8221; — <em>tĕbûnāh</em> (discernment/insight) is the practical wisdom to understand situations. <em>Wĕrab maʿăśaqqôt</em> = &#8220;and a great oppressor.&#8221; The connection is diagnostic: lack of discernment and oppression are linked — the ruler who cannot think cannot govern and so resorts to force. <em>Śônēʾ beṣaʿ yaʾărîk yāmîm</em> = &#8220;but whoever hates unjust gain will prolong his days.&#8221></p>",
    "17": "<p><em>ʾĀdām ʿāšûq bĕdam-nepeš</em> = &#8220;A man burdened with the guilt of blood (<em>dam-nepeš</em>) of another person&#8221; — <em>nepeš</em> (H5315) here is &#8220;life/person&#8221; — the whole living person whose blood has been shed. <em>ʿAd-bôr yānûs ʾal-yitměkû-bô</em> = &#8220;will flee to the pit; let no one help him.&#8221; The blood-guilt pursues the killer to Sheol (<em>bôr</em>, the pit/grave); the prohibition on helping him is a community protection against harboring a fugitive blood-guiltsman.</p>",
    "18": "<p><em>Hôlēk tāmîm yiwwāšēaʿ</em> = &#8220;Whoever walks with integrity (<em>tōm</em>) will be saved&#8221; — <em>yāšaʿ</em> (be saved/delivered) — the salvation vocabulary applied to moral integrity; the root is the same as <em>yēšûʿāh</em> (salvation/Joshua/Jesus). <em>Wĕniʿqaš dĕrākayim yippôl bĕ'aḥat</em> = &#8220;but the one who is crooked in his ways (<em>niʿqaš</em>) will fall at once.&#8221> <em>Niʿqaš</em> (crooked/twisted-double paths) is the literal image of walking a zig-zag path.</p>",
    "19": "<p><em>ʿŌbēd ʾadmātô yiśbaʿ lāḥem</em> = &#8220;Whoever works his land will have plenty of bread&#8221; — agricultural labor as the paradigm of productive work. <em>Ûmĕraddēp rêqîm yiśbaʿ rîš</em> = &#8220;but whoever chases empty pursuits (<em>rêqîm</em>, empty things) will have plenty of poverty&#8221; — the bitter irony: the diligent worker has plenty of bread; the idle chaser has plenty of poverty. The parallel structure lets the word &#8220;plenty&#8221; (<em>yiśbaʿ</em>, be sated) carry the contrast.</p>",
    "20": "<p><em>ʾÎš ʾĕmûnôt rab-bĕrākôt</em> = &#8220;A faithful man (<em>ʾĕmûnôt</em>, faithfulnesses) will abound with blessings&#8221; — <em>ʾĕmûnāh</em> (faithfulness/reliability) is the character quality of consistent trustworthiness. <em>Wĕʾāṣ lĕhāʿăšîr lō' yinnāqeh</em> = &#8220;but whoever is eager/hasty to get rich will not go unpunished&#8221; — the urgency of wealth-seeking corrupts the faithful character; get-rich-quick schemes require cutting ethical corners.</p>",
    "21": "<p><em>Hakkēr-pānîm lō'-ṭôb</em> = &#8220;To show partiality (<em>hakkēr pānîm</em>, recognize/acknowledge a face) is not good&#8221; — the idiom for favoritism: granting favorable treatment because you recognize (know) someone. <em>Ûʿal-pat leḥem yipšaʿ-gāber</em> = &#8220;yet for a mere piece of bread a man will commit a wrong.&#8221; The smallness of the inducement is the point: partiality is so deeply embedded that it takes almost nothing to activate it.</p>",
    "22": "<p><em>Niḇhāl lĕhôn ʾîš rāʿ ʿāyin</em> = &#8220;A man who is eager/hasty for wealth is a man of an evil eye&#8221; — <em>raʿ ʿāyin</em> (evil eye) is the Hebrew idiom for stinginess/greed (contrast <em>ṭôb ʿāyin</em>, good eye = generosity, in 22:9). <em>Wĕlō' yēdaʿ kî-ḥeser yĕbōʾennû</em> = &#8220;and does not know (<em>yādaʿ</em>, H3045) that poverty is coming for him.&#8221> His greed blinds him to the trajectory his greed creates.</p>",
    "23": "<p><em>Môkîaḥ ʾādām ʾaḥărāy ḥēn yimṣā'</em> = &#8220;Whoever rebukes a person will afterward find more favor (<em>ḥēn</em>) than the one who flatters&#8221; — <em>ḥēn</em> (H2580, dispute_level=2): grace/favor/charm/kindness. The dispute is whether it describes the approval the rebuker receives from the rebuked person in retrospect, or from the community. The MKT &#8220;more favor&#8221; is right: honest rebuke, though painful initially, earns genuine relational capital that flattery never builds.</p>",
    "24": "<p><em>Gōzēl ʾābîw wĕʾimmô wĕʾōmēr ʾên-pāšaʿ</em> = &#8220;Whoever robs his father or mother and says &#8216;There is nothing wrong with it&#8217;&#8221; — <em>gāzal</em> (rob/seize by violence) applied to parents; the rationalizing speech &#8216;ên pāšaʿ&#8217; (no transgression) is the hallmark of hardened conscience. <em>Ḥābēr hûʾ lĕʾîš mašḥît</em> = &#8220;is a partner to a man who destroys&#8221; — the rationalizer is classified with the destroyer; the self-justification does not change the moral category.</p>",
    "25": "<p><em>Raḥab-nepeš yĕgāreh mādon</em> = &#8220;A greedy person (<em>raḥab-nepeš</em>, wide/expanded of appetite) stirs up strife&#8221; — <em>nepeš</em> (H5315) here = appetite/desire; the &#8220;wide-souled&#8221; person whose desires have no limit. <em>Ûbôṭēaḥ ʿal-YHWH yĕdušshan</em> = &#8220;but whoever trusts in the LORD will prosper/be fat (<em>dāšan</em>).&#8221; The one who trusts YHWH (rather than expanding their own appetite) receives the prosperity the greedy person grasps after.</p>",
    "26": "<p><em>Bôṭēaḥ bĕlibbô hûʾ kĕsîl</em> = &#8220;Whoever trusts his own heart is a fool&#8221; — the <em>lēb</em> (heart/mind) as the center of reasoning and willing; self-trust of this kind is specifically named folly. <em>Wĕhôlēk bĕḥokmāh hûʾ yimmālēṭ</em> = &#8220;but whoever walks in wisdom will be kept safe&#8221; — <em>yimmālēṭ</em> (escape/be delivered). The contrast is between two sources of guidance: self-referential trust vs. wisdom-shaped walking.</p>",
    "27": "<p><em>Nôtēn lārāš ʾên mahsôr</em> = &#8220;Whoever gives to the poor will not lack (<em>mahsôr</em>)&#8221; — the generosity paradox: giving creates no deficit for the giver. <em>Wĕmaʿlîm ʿênāyw rab-mĕʾērôt</em> = &#8220;but whoever hides his eyes from them will get many curses.&#8221; <em>Maʿlîm ʿênāyw</em> = averting the gaze — the deliberate non-seeing that enables inaction. The curses are both social (from the poor) and divine (for ignoring covenant obligation).</p>",
    "28": "<p><em>Bĕqûm rĕšāʿîm yissātēr ʾādām</em> = &#8220;When the wicked rise to power, people go into hiding&#8221; — the public withdrawal described in v12 now bookends the chapter. <em>Ûbĕʾābĕdām yirbû ṣaddîqîm</em> = &#8220;but when the wicked perish, the righteous multiply.&#8221> The righteous community's growth is directly linked to the removal of wicked power: oppression suppresses flourishing; its removal allows multiplication. The chapter closes with this political-theological vision.</p>"
  },
  "29": {
    "1": "<p><em>ʾÎš tôkaḥôt maqšeh-ʿōrep</em> = &#8220;A man who is often reproved (<em>tôkaḥôt</em>, reproofs) yet stiffens his neck (<em>maqšeh-ʿōrep</em>)&#8221; — <em>qāšāh ʿōrep</em> (stiffen the neck) is the covenant-violation posture of Deut 31:27; the neck-stiffening of the wilderness generation. <em>Peta' yiššābēr wĕʾên marpēʾ</em> = &#8220;will suddenly be broken beyond remedy.&#8221> <em>Marpēʾ</em> (healing, remedy) — the absence of remedy after the break; the repetition of reproof without response exhausts the window of healing.</p>",
    "2": "<p><em>Birĕbôt ṣaddîqîm yiśmaḥ hāʿām</em> = &#8220;When the righteous are in authority, the people rejoice&#8221; — the political theology of joy: righteous rule produces communal flourishing that is experienced as joy. <em>Ûbimšōl rāšāʿ yēʾānah ʿām</em> = &#8220;when the wicked rule, the people groan.&#8221> <em>ʾĀnaḥ</em> (groan/sigh) — the bodily expression of distress under oppressive governance. The groan of the people under the wicked is the inverse of their song under the righteous.</p>",
    "3": "<p><em>ʾÎš ʾōhēb ḥokmāh yĕśammaḥ ʾābîw</em> = &#8220;Whoever loves wisdom brings his father joy&#8221; — the parent-child wisdom theme of 10:1. <em>Wĕrōʿēh zônôt yĕʾabbēd hôn</em> = &#8220;but a companion of prostitutes wastes his wealth (<em>hôn</em>).&#8221> <em>ʾābad</em> (perish/destroy/lose) applied to <em>hôn</em> (wealth/substance) — the seductive woman of ch7 as an economic as well as spiritual destroyer.</p>",
    "4": "<p><em>Melek bĕmišpāṭ yaʿămîd ʾāreṣ</em> = &#8220;A king (<em>melek</em>, H4428, dispute_level=2) establishes the land through justice&#8221; — <em>šāphaṭ</em> (justice) as the architectural force of political stability. <em>Wĕ'îš tĕrûmôt yehersennāh</em> = &#8220;but one who accepts bribes (<em>tĕrûmôt</em>, tribute-offerings/bribes) tears it down.&#8221> The term <em>tĕrûmāh</em> normally means the priestly offering set apart; its ironic use for bribes suggests that a bribe is a tribute offered to the wrong altar — corrupting what should be holy judgment.</p>",
    "5": "<p><em>Geber meḥallēq ʿal-rēʿēhû</em> = &#8220;A man who flatters his neighbor&#8221; — <em>ḥālaqqāh</em> (smooth/flattery) — the smooth speech that disarms honest assessment. <em>Rešet pôrēś ʿal-pĕʿāmāyw</em> = &#8220;spreads a net for his feet.&#8221> The flatterer's smooth words are a trap laid under the feet of the one being praised; the danger of flattery is that it prevents the flattered person from seeing clearly and so they walk into what they cannot see.</p>",
    "6": "<p><em>Bĕpeša' ʾîš-rāʿ môqēš</em> = &#8220;In the transgression of an evil man there is a snare&#8221; — the wicked person's sin is itself a trap that catches them. <em>Wĕṣaddîq yārûn wĕyiśmāḥ</em> = &#8220;but the righteous sing (<em>rûn</em>) and rejoice.&#8221> <em>Rûn</em> (shout for joy/sing a ringing cry) — the vocal expression of liberation; the righteous person moves through the same territory the wicked stumbles in and sings rather than stumbles.</p>",
    "7": "<p><em>Yōdēaʿ ṣaddîq dîn dallîm</em> = &#8220;The righteous man knows (<em>yāddaʿ</em>, H3045) the cause of the poor&#8221; — <em>yādaʿ</em> here carries the full weight of &#8220;care-about&#8221; (as in &#8220;the LORD knows the way of the righteous,&#8221; Ps 1:6): not mere intellectual knowledge but engaged concern. <em>Rāšāʿ lō'-yābîn dāʿat</em> = &#8220;the wicked man does not care to understand it.&#8221> The refusal to understand is itself a moral act: willful epistemic distance from the poor's situation is wickedness.</p>",
    "8": "<p><em>ʾAnšê lāṣôn yāpîḥû qiryāh</em> = &#8220;Scornful men inflame (<em>pûaḥ</em>, blow/breathe) a city&#8221; — <em>pûaḥ</em> (blow like wind) applied to city-inflaming: the scornful breathe on the coals of social conflict until a city burns. <em>Waḥăkāmîm yāšîbû ʾāp</em> = &#8220;but wise men turn away anger (<em>ʾāp</em>, nose/anger).&#8221> The same nose-image: <em>ʾāp</em> (wrath, lit. the snorting nose) is turned back by wisdom; the hot breath of scorn is countered by the cooling counsel of the wise.</p>",
    "9": "<p><em>ʾÎš ḥākām niśpāṭ ʾet-ʾîš ʾĕwîl</em> = &#8220;If a wise man contends in court (<em>šāphaṭ</em>, H8199, dispute_level=2) with a fool&#8221; — <em>šāphaṭ</em> carries the range of judge/govern/decide; in the court setting it is &#8220;to dispute/plead.&#8221> <em>Wĕrāgaz wĕśāḥaq wĕʾên nāḥat</em> = &#8220;the fool only rages and laughs, and there is no quiet.&#8221> The fool's courtroom behavior — alternating between rage and dismissive laughter — makes rational proceedings impossible; the wise man's case cannot be heard.</p>",
    "10": "<p><em>ʾAnšê dāmîm yiśnĕʾû-tām</em> = &#8220;Bloodthirsty men hate the upright (<em>tām</em>, blameless/complete)&#8221; — the blameless person is the target of those who live by violence; innocence provokes those whose self-justification depends on everyone being as guilty as they are. <em>Wîšārîm yĕbaqqĕšû napšô</em> = &#8220;but the righteous seek to protect his life (<em>nepeš</em>, H5315).&#8221> <em>Nepeš</em> here = life/person; the righteous protect the vulnerable blameless person.</p>",
    "11": "<p><em>Kol-rûḥô yôṣîʾ kĕsîl</em> = &#8220;A fool vents all his spirit/feelings (<em>rûaḥ</em>, H7307)&#8221; — <em>rûaḥ</em> has the range: spirit / breath / wind / disposition / feeling. Here &#8220;all his spirit&#8221; = every impulse, emotion, and reaction immediately expressed. <em>Wĕḥākām bĕʾāḥôr yĕšabbĕḥennāh</em> = &#8220;but a wise man quietly holds it back.&#8221> <em>Šābaḥ</em> (calm/still/hold back) — the same root used in Ps 89:9 of YHWH stilling the sea: wisdom rules the inner weather the way YHWH rules the storm.</p>",
    "12": "<p><em>Mōšēl maqšîb ʿal-dĕbar-šāqer</em> = &#8220;If a ruler listens to lies&#8221; — the leader who opens himself to false reports has already compromised the governing function. <em>Kol-mĕšārĕtāyw rĕšāʿîm</em> = &#8220;all his officials become wicked.&#8221> The moral ecology of leadership: a ruler who tolerates lying selects for wicked officials who survive by telling him what he will accept. Corruption propagates downward from receptive leadership.</p>",
    "13": "<p><em>Rāš wĕʾîš tĕkākîm nipgāšû</em> = &#8220;The poor man and the oppressor have this in common&#8221; — the unexpected juxtaposition. <em>Mĕʾîr ʿênê-šĕnêhem YHWH</em> = &#8220;the LORD gives light to the eyes of both.&#8221> The divine gift of sight (life-capacity) is democratically given — oppressor and oppressed both receive the same basic endowment from YHWH. This is not moral equivalence but creational equality: YHWH is Creator of both.</p>",
    "14": "<p><em>Melek šôpēṭ bĕʾĕmet dallîm</em> = &#8220;A king (<em>melek</em>, H4428) who judges (<em>šāphaṭ</em>, H8199) the poor with faithfulness (<em>ʾĕmet</em>, H571, dispute_level=2)&#8221; — three disputed terms converge. <em>ʾĕmet</em> ranges across truth/faithfulness/reliability; here it describes the quality of the king's judgment toward the powerless. <em>Kissĕʾô lāʿad yekkôn</em> = &#8220;his throne will be established forever.&#8221> The stability of the throne is directly proportional to the faithfulness of its justice toward the most vulnerable.</p>",
    "15": "<p><em>Šēbeṭ wĕtôkaḥat yittēn ḥokmāh</em> = &#8220;The rod and reproof give wisdom&#8221; — the dual instruments of formation: <em>šēbeṭ</em> (rod/staff, physical correction) and <em>tôkaḥat</em> (verbal reproof). <em>Wĕnaʿar mĕšullāḥ mēbîš ʾimmô</em> = &#8220;but a child left to himself (<em>mĕšullāḥ</em>, sent away/released) brings shame to his mother.&#8221> The released child — uncorrected, unformed — is a community liability; his mother bears the social cost of his formation failure.</p>",
    "16": "<p><em>Birĕbôt rĕšāʿîm yirbeh-pāšaʿ</em> = &#8220;When the wicked increase (<em>rābāh</em>), transgression increases&#8221; — multiplication of wicked persons generates its own momentum: wickedness begets wickedness in a social amplification effect. <em>Wĕṣaddîqîm bĕmappaltām yirʾû</em> = &#8220;but the righteous will see their downfall.&#8221> The righteous are spectators of divine judgment on the wicked; they do not need to avenge themselves.</p>",
    "17": "<p><em>Yassēr binkā wînîḥekā</em> = &#8220;Discipline your son and he will give you rest&#8221; — <em>yāsar</em> (discipline/chastise) as the formative act that produces peace in the parent. <em>Wĕyittēn maʿadannîm lĕnapšekā</em> = &#8220;he will give delight (<em>maʿadannîm</em>, delicacies/luxuries) to your soul (<em>nepeš</em>, H5315).&#8221> <em>Nepeš</em> here = self/inner life; the disciplined son's character is the parent's spiritual luxury — the inner satisfaction deeper than material pleasure.</p>",
    "18": "<p><em>Bĕʾên ḥāzôn yippāraʿ ʿām</em> = &#8220;Where there is no prophetic vision (<em>ḥāzôn</em>), the people are unrestrained (<em>pāraʿ</em>)&#8221; — <em>ḥāzôn</em> is the technical prophetic term for divine revelation received in a vision (Isa 1:1; Obad 1:1). The absence of prophetic word dissolves social restraint; without revelation the moral framework loses its authoritative grounding. <em>Wĕšōmēr tôrāh ʾašrêhû</em> = &#8220;but blessed is the one who keeps the law.&#8221> The pairing of prophetic vision and <em>tôrāh</em>-keeping as dual sources of order is the governing theme of the verse.</p>",
    "19": "<p><em>Bidbārîm lō'-yiwwāsēr ʿābed</em> = &#8220;A servant cannot be corrected by mere words&#8221; — the limits of verbal instruction in certain contexts. <em>Kî yābîn wĕʾên maʿăneh</em> = &#8220;for he understands but will not respond.&#8221> The servant who hears and understands but refuses to respond illustrates the gap between intellectual reception and behavioral change — understanding without transformed will.</p>",
    "20": "<p><em>Ḥāzîtā ʾîš ʾāṣ bidbārāyw</em> = &#8220;Do you see a man who is hasty (<em>ʾūṣ</em>) in his words?&#8221> — <em>ʾūṣ</em> (hasten/urge) — the urgency of words not thought through. <em>Tiqwāh lĕkĕsîl mimmennû</em> = &#8220;There is more hope for a fool than for him.&#8221> The highest negative comparison in Proverbs: to be ranked worse than the fool is to be classified as a special case of recklessness. The hasty-tongued person is beyond the fool because the fool at least may be ignorant; the hasty speaker knows but does not pause.</p>",
    "21": "<p><em>Mĕpannēq minnōʿar ʿabdô</em> = &#8220;Whoever pampers (<em>pānaḳ</em>) his servant from childhood&#8221; — <em>pānaḳ</em> (pamper/indulge/coddle) — the excessive softening of the servant's formation. <em>Wĕʾaḥărîtô yihyeh māndôn</em> = &#8220;will find that in the end he has become like a son.&#8221> The indulged servant loses the working relationship and claims familial entitlements; overly soft treatment erodes proper distinctions.</p>",
    "22": "<p><em>ʾÎš-ʾap yĕgāreh mādon</em> = &#8220;An angry man (<em>ʾap</em>, nose/anger) stirs up strife&#8221; — the nose-anger idiom again (cf. v8): the short-tempered person is a chronic strife-generator. <em>Ûbaʿal ḥēmāh rab-pāšaʿ</em> = &#8220;and a hot-tempered man (<em>baʿal ḥēmāh</em>, master of wrath) abounds in transgression.&#8221> The hot-tempered person's transgression multiplies because anger bypasses the moral deliberation that restrains sin.</p>",
    "23": "<p><em>Gaʾăwat ʾādām tašpîlennû</em> = &#8220;A man's pride (<em>gaʾăwāh</em>) will bring him low&#8221; — <em>gaʾăwāh</em> (pride/arrogance/majesty) — the same root as divine majesty when applied to YHWH (Ps 93:1), but here human presumption. <em>Ûšĕpal rûaḥ yitmōk kābôd</em> = &#8220;but the one who is humble of spirit (<em>šĕpal rûaḥ</em>) will obtain honor (<em>kābôd</em>).&#8221> Both <em>rûaḥ</em> (H7307) and <em>kābôd</em> (H3519, dispute_level=2) are contested: <em>rûaḥ</em> = spirit/breath/disposition; <em>kābôd</em> = honor/glory/weight. The humble-spirited person receives the weighty honor that the proud person grasps after and loses.</p>",
    "24": "<p><em>Ḥôlēq im-gannāb śônēʾ napšô</em> = &#8220;Whoever partners with a thief hates himself (<em>śônēʾ napšô</em>)&#8221; — the self-destructive logic of complicity: partnering with wickedness is hatred toward one's own life. <em>ʾAlāh yišmaʿ wĕlō' yaggîd</em> = &#8220;he hears the curse but does not disclose it.&#8221> The silent witness who hears a public oath-curse (calling for disclosure of wrongdoing) and refuses to testify — both guilty participant and cowardly bystander.</p>",
    "25": "<p><em>Ḥardat ʾādām yittēn môqēš</em> = &#8220;The fear of man (<em>ḥardat ʾādām</em>) lays a snare&#8221; — human-directed fear as a trap; the anxiety about what people will think or do constrains action and leads into self-protective compromise. <em>Ûbôṭēaḥ baYHWH yĕśuggāb</em> = &#8220;but whoever trusts in YHWH (H3068) is kept safe (<em>śāgab</em>, set on high/made inaccessible).&#8221> <em>Śāgab</em> = to be placed on an inaccessible height — beyond the reach of the snare. The trust that transfers fear from humans to YHWH produces the elevation the snare cannot reach.</p>",
    "26": "<p><em>Rabbîm mĕbaqqĕšîm pĕnê-môšēl</em> = &#8220;Many seek the ruler's favor (<em>pĕnê-môšēl</em>, the face of the ruler)&#8221; — court-seeking as the normal mode of obtaining advantage; <em>bāqaš pānîm</em> = to seek the face = to appeal for access/approval. <em>Ûmêʾet YHWH mišpaṭ-ʾîš</em> = &#8220;but justice for a man comes from YHWH.&#8221> The verse redirects the petitioner: the court of ultimate appeal is not the human ruler but YHWH. Human rulers can be circumvented, corrupted, or inaccessible; YHWH's justice is the final and reliable recourse.</p>",
    "27": "<p><em>Tôʿăbat ṣaddîqîm ʾîš ʿāwel</em> = &#8220;An unjust man is an abomination to the righteous&#8221; — the mutual repulsion of righteousness and wickedness: the <em>tôʿēbāh</em> (abomination) that YHWH feels toward wickedness (12:22; 15:8) is felt by the righteous as well — moral revulsion is a feature of righteous character. <em>Wĕtôʿăbat rāšāʿ yĕšar-dārek</em> = &#8220;and the one who walks uprightly is an abomination to the wicked.&#8221> The mutual abomination is symmetric: righteousness is intolerable to wickedness as wickedness is to righteousness.</p>"
  },
  "30": {
    "1": "<p><em>Dibrê ʾāgûr ben-yāqeh hammassāʾ</em> = &#8220;The words of Agur son of Jakeh. The oracle (<em>massāʾ</em>).&#8221> <em>Massāʾ</em> is both &#8220;burden&#8221; and &#8220;oracle/utterance&#8221; — the technical term for prophetic pronouncements (Isa 13:1; Nah 1:1). Agur and Jakeh do not appear elsewhere in the OT; the names and the following verses suggest a non-Israelite sage of recognized wisdom, or a pseudonymous framework. The speaker claims to have addressed &#8216;Ithiel&#8217; and &#8216;Ucal&#8217; (persons or place names debated). The oracle framework authorizes what follows as more than personal musing.</p>",
    "2": "<p><em>Kî baʿar ʾānōkî mêʾîš</em> = &#8220;Surely I am more brutish (<em>baʿar</em>, like a beast/animal) than any man&#8221; — <em>baʿar</em> (animal/beast) as a self-descriptor: the radical self-deprecation of the sage who has reached the limits of wisdom and acknowledges the gap. <em>Wĕlō' bînat ʾādām lî</em> = &#8220;and I do not have the understanding of a human being.&#8221> This is not false modesty but the apophatic starting point: wisdom begins with acknowledging what one does not and cannot know by human means alone.</p>",
    "3": "<p><em>Wĕlō'-lāmadtî ḥokmāh</em> = &#8220;I have not learned wisdom&#8221; — Agur's disclaimer intensifies: not only brutish but untaught. <em>Wĕdaʿat qĕdōšîm ʾēdāʿ</em> = &#8220;nor have I knowledge (<em>dāʿat</em>) of the Holy One (<em>qĕdōšîm</em>).&#8221> <em>Qĕdōšîm</em> (plural) applied to God — either an intensive plural of majesty (the uniquely holy One) or acknowledging the heavenly council; the MKT &#8220;Holy One&#8221; (singular) follows the most common interpretation. <em>Yādaʿ</em> (H3045, dispute_level=2) here = intimate relational knowledge, not merely propositional awareness.</p>",
    "4": "<p><em>Mî ʿālāh-šāmayim wayyērēd</em> = &#8220;Who has ascended to heaven and come back down?&#8221> — the rhetorical questions of vv4-5 are among the most theologically charged in Proverbs. The sequence — ascend heaven, gather wind in fists, wrap waters in garment, establish earth's ends — describes divine transcendence beyond all human capacity. <em>Mah-šĕmô ûmah-šem-bĕnô</em> = &#8220;What is his name, and what is his son's name (<em>šem-bĕnô</em>)?&#8221> — the mention of a &#8220;son&#8221; alongside the Creator God is unique in the OT wisdom corpus; it generates Christological reflection in the Christian tradition (Heb 1:2-3 applies creation-language to the Son). The verse acknowledges that the answer to its own question exceeds human wisdom.</p>",
    "5": "<p><em>Kol-ʾimrat ʾĕlôah ṣĕrûpāh</em> = &#8220;Every word of God (<em>ʾĕlôah</em>) proves true (<em>ṣārap</em>, is refined/tested)&#8221; — <em>ṣārap</em> (refine/smelt/test) used of divine speech: as silver is refined of dross in the crucible (Ps 12:6), so every divine utterance is pure of error. <em>Māgēn hûʾ laḥōsîm bô</em> = &#8220;he is a shield to those who take refuge in him.&#8221> Confidence in the reliability of divine speech produces the trust that finds YHWH as shield — the epistemological trustworthiness of God's word is the foundation of personal refuge.</p>",
    "6": "<p><em>ʾAl-tôsēp ʿal-dĕbārāyw</em> = &#8220;Do not add to his words (<em>dĕbārāyw</em>)&#8221; — the prohibition against supplementing divine speech with human invention echoes the Deuteronomic prohibition (Deut 4:2; 12:32). <em>Pen-yôkîaḥ bĕkā wĕnikzabĕtā</em> = &#8220;lest he rebuke you and you be found a liar.&#8221> The addition of human words to divine speech invites divine rebuke — the human additions are measured against the pure divine word (v5) and found to be the lies they are.</p>",
    "7": "<p><em>Šĕtayim šāʾaltî mêʾittāk</em> = &#8220;Two things I ask of you; do not deny them to me before I die&#8221; — the prayer formula that introduces vv8-9: a numbered-list prayer of specific requests. Agur's prayer is notable for its concrete, non-triumphalist character — asking not for greatness but for moral safety. The double petition is framed by mortality awareness: &#8220;before I die.&#8221></p>",
    "8": "<p><em>Šāwĕʾ ûdbar kāzāb harḥēq mimmennî</em> = &#8220;Keep falsehood and lies (<em>šāwĕʾ ûdbar kāzāb</em>) far from me&#8221; — <em>šāwĕʾ</em> (emptiness/vanity/falsehood) and <em>kāzāb</em> (lie/deception) — the prayer to be kept from both empty vanity and deliberate lying. <em>Rēš wĕʿōšer ʾal-tittĕn-lî</em> = &#8220;give me neither poverty nor riches (<em>ʿōšer</em>).&#8221> The prayer for the middle way — the rare wisdom petition that refuses both extremes, knowing that both carry spiritual risk.</p>",
    "9": "<p><em>Pen-ʾeśbaʿ wĕkiḥaštî wĕʾāmartî mî YHWH</em> = &#8220;lest I be full and deny you, saying &#8216;Who is the LORD (<em>YHWH</em>, H3068)?&#8217;&#8221; — the danger of satiety: fullness produces the arrogant forgetting of God that Deut 8:12-14 warns Israel about. <em>Û-pen-ʾiwwārēš wĕgānabĕtî wĕtāpaśtî šēm ʾĕlōhāy</em> = &#8220;or lest I be poor and steal and profane (<em>tāpas</em>) the name of my God (<em>ʾĕlōhāy</em>, H430).&#8221> <em>ʾĕlōhîm</em> (H430) — grammatically plural but taking singular verbs; the name &#8220;my God&#8221; is personalized. The prayer holds together two theological dangers: prosperity-induced atheism and poverty-induced theft that dishonors the divine name.</p>",
    "10": "<p><em>ʾAl-talsēn ʿebed ʾel-ʾădōnāyw</em> = &#8220;Do not slander (<em>lāšan</em>, use the tongue against) a servant to his master&#8221; — <em>lāšan</em> is literally &#8220;to tongue&#8221; someone — to use speech as an instrument of harm. <em>Pen-yĕqallĕlekā wĕʾāšāmĕtā</em> = &#8220;lest he curse you and you be found guilty.&#8221> The curse of the slandered servant (perhaps invoking divine justice) rebounds on the slanderer; interfering in the master-servant relationship carries its own accountability.</p>",
    "11": "<p><em>Dôr ʾābîw yĕqallēl</em> = &#8220;There is a generation that curses its father&#8221; — the first of four &#8216;generation&#8217; (<em>dôr</em>) portraits (vv11-14), each describing a type of moral failure. The father-cursing generation inverts the fifth commandment (Exod 20:12); <em>wĕʾet-ʾimmô lō'-yĕbārēk</em> = &#8220;and does not bless its mother.&#8221> The double failure — active cursing of the father, passive withholding of blessing from the mother — covers both poles of parental dishonor.</p>",
    "12": "<p><em>Dôr ṭāhôr bĕ'ênāyw</em> = &#8220;There is a generation that is pure in its own eyes&#8221; — the self-deception of the morally filthy who believe themselves clean. <em>Ûmĕṣōʾātô lō' ruḥāṣ</em> = &#8220;but has not been washed from its filth.&#8221> The purification language (<em>rāḥaṣ</em>, wash) points to the ritual-purity framework: the generation that has never submitted to cleansing stands before God as genuinely dirty despite its own assessment. The verse anticipates the prophetic critique of self-righteous religion (Isa 1:16; Jer 2:22).</p>",
    "13": "<p><em>Dôr māh-rāmû ʿênāyw</em> = &#8220;There is a generation — how lofty are their eyes (<em>rāmû ʿênāyw</em>)!&#8221> — <em>rûm ʿênayim</em> (high/lifted eyes) is the idiom for arrogant disdain; the eyes that look down because they are looking down from a superior position. <em>Wĕʿapʿappāyw yinnāśeʾû</em> = &#8220;how high their eyelids are lifted!&#8221> The eyelids (<em>ʿapʿappayim</em>, the fluttering eyelids) are another idiom for contemptuous staring. The generation portrait is one of physical pride-posturing that expresses inner arrogance.</p>",
    "14": "<p><em>Dôr ḥărābôt šinnāyw</em> = &#8220;There is a generation whose teeth are swords&#8221; — the fourth and most violent generation: their teeth are swords and their fangs are knives, devouring the poor and needy from the earth. The eating-as-violence metaphor makes social oppression visceral: the powerful consume the weak the way predatory animals devour prey. <em>Leʾăkōl ʿăniyyîm mêʾereṣ wĕʾebyônîm mêʾādām</em> = &#8220;to devour the poor from the earth and the needy from among men.&#8221></p>",
    "15": "<p><em>Laʿălûqāh šĕtê bānôt hav hav</em> = &#8220;The leech has two daughters: &#8216;Give&#8217; and &#8216;Give&#8217;&#8221; — the leech (<em>ʿalûqāh</em>, a hapax legomenon; the blood-sucking worm or vampire) as an image of insatiable demand. The transition to numerical sayings: &#8220;Three things are never satisfied; four never say &#8216;Enough.&#8217;&#8221; The numerical formula (X+1) is characteristic of Agur's style (cf. vv18,21,24,29) — it creates anticipation and climax.</p>",
    "16": "<p><em>Šĕʾôl wĕʾōṣer reḥem</em> = &#8220;Sheol, the barren womb, the earth that is never satisfied with water, and the fire&#8221; — the four things never satisfied: Sheol's appetite for the dead, the barren womb's longing for children, the earth's thirst that cannot be permanently quenched, and fire's insatiable consumption. The combination moves from death to fertility to earth to fire — the full range of natural forces that exceed human capacity to fill or satisfy.</p>",
    "17": "<p><em>ʿAyin tileʿag lĕʾāb</em> = &#8220;The eye that mocks (<em>lāʿag</em>) a father and scorns to obey a mother&#8221; — the eye as the instrument of contempt (linking back to vv13-14). <em>Wĕyiqrûhā ʿōrbê-naḥal wĕyōʾklûhā bĕnê-nāšer</em> = &#8220;will be picked out by the ravens of the valley and eaten by the vultures.&#8221> The graphic imagery of unburied death: the eye that showed contempt for parents will be plucked out and devoured by carrion birds — the ultimate reversal of honor and the completion of shame.</p>",
    "18": "<p><em>Šĕlōšāh hēmmāh niplĕʾû mimmennî</em> = &#8220;Three things are too wonderful (<em>niplāʾ</em>) for me; four I do not understand (<em>yādaʿ</em>, H3045, dispute_level=2)&#8221> — <em>yādaʿ</em> here = comprehend/master. The &#8220;wonderful&#8221; (<em>pālāʾ</em>) is the same root as God's works being &#8220;wonders&#8221; (Ps 77:11); Agur applies the vocabulary of divine mystery to natural phenomena. The four wonders are presented as things that exceed his understanding despite their visibility.</p>",
    "19": "<p><em>Derek hāneśer baššāmāyim</em> = &#8220;the way of an eagle in the sky&#8221; — the four wonders: eagle in sky, serpent on rock, ship in sea, and man with young woman. What they share is the leaving of no trace: the eagle, snake, and ship pass through their medium without permanent mark; the way of a man with a maiden is similarly impenetrable in its movement. The fourth (&#8220;the way of a man with a young woman&#8221;) gives the series its climax and its interpretive key: the wonder of intimate relationship is as mysterious as natural phenomena.</p>",
    "20": "<p><em>Kēn derek ʾiššāh mĕnāʾāpet</em> = &#8220;Such is the way of an adulteress&#8221; — the transition from wonder to warning: the adulteress mimics the wonder of the man-with-maiden passage but with moral inversion. <em>ʾākĕlāh ûmāḥătāh pîhā wĕʾāmĕrāh lō'-pāʿaltî ʾāwen</em> = &#8220;she eats and wipes her mouth and says, &#8216;I have done nothing wrong.&#8217;&#8221> The wiping of the mouth erases the trace, exactly as the four wonders left no trace — but here the trace-erasure is self-serving denial of moral reality.</p>",
    "21": "<p><em>Taḥat šālôš rāgĕzāh ʾereṣ</em> = &#8220;Under three things the earth trembles (<em>rāgaz</em>); under four it cannot bear up (<em>śāʾ</em>)&#8221; — the second four-part series in Agur's oracle, this time with negative-social focus. The earth's trembling is the physical response to the inversion of proper social order; the cosmos reacts to the violation of its built-in hierarchies.</p>",
    "22": "<p><em>Taḥat ʿebed kî yimlôk</em> = &#8220;a servant when he reigns&#8221; — the first of four social inversions: servant become king. <em>Wĕnābāl kî śābaʿ lāḥem</em> = &#8220;and a fool when he is full of food.&#8221> <em>Nābāl</em> (fool/knave) — the morally deficient person. The earth trembles not at the events themselves but at the disproportionate results they produce: a satiated fool is more dangerous than a hungry one.</p>",
    "23": "<p><em>Taḥat śĕnûʾāh kî tibbaʿēl</em> = &#8220;an unloved woman when she gets a husband&#8221; — the third inversion: the socially overlooked woman who suddenly gains the position of wife and uses it for vengeance or domination. <em>Wĕšipḥāh kî-tîrāš gĕbirtāh</em> = &#8220;and a maidservant who displaces (<em>yāraš</em>, inherit/dispossess) her mistress.&#8221> The servant who inherits the mistress's position — the final inversion of domestic order. All four earth-trembling situations involve the abrupt reversal of social position without the formation of character to match.</p>",
    "24": "<p><em>ʾArbaʿāh hēm qĕṭannê-ʾāreṣ</em> = &#8220;Four things on earth are small (<em>qāṭan</em>), but they are exceedingly wise (<em>mĕḥukkāmîm mĕʾōd</em>)&#8221; — the third four-part series, this time celebratory: smallness with wisdom exceeds greatness without it. The four creatures will demonstrate that size and strength are not the measures of true wisdom.</p>",
    "25": "<p><em>Hanĕmālîm ʿam lō'-ʿāz</em> = &#8220;the ants are a people not strong (<em>ʿāz</em>), yet they prepare their food in the summer&#8221; — the ant as the paradigm of foresight-wisdom: they plan for winter during summer abundance. The ant of 6:6-8 reappears; here in the context of small-but-wise creatures it demonstrates that wisdom-planning compensates for physical weakness.</p>",
    "26": "<p><em>Šĕpannîm ʿam lō'-ʿāṣûm</em> = &#8220;the rock badgers are a feeble people (<em>lō'-ʿāṣûm</em>, not powerful), yet they make their homes in the cliffs&#8221; — the rock badger (coney/hyrax) compensates for vulnerability with strategic placement: they live in the inaccessible cliffs where predators cannot easily reach. Wisdom exploits environment; the weak creature uses terrain the strong creature ignores.</p>",
    "27": "<p><em>Hāʾarbeh ʾên melek (<em>melek</em>, H4428, dispute_level=2)</em> = &#8220;the locusts have no king (<em>melek</em>)&#8221; — the absence of hierarchical leadership does not prevent the locusts from marching in perfect formation. <em>Wĕyēṣēʾ ḥōṣēṣ kullô</em> = &#8220;yet all of them march out in formation.&#8221> The locust swarm without a king demonstrates that effective collective action can arise from distributed wisdom rather than central authority. The mention of <em>melek</em> is ironic in context: the animal without a king does what kings fail to achieve.</p>",
    "28": "<p><em>Śĕmāmît bĕyādayim tĕtappēś</em> = &#8220;the lizard (<em>śĕmāmît</em>, a hapax — likely a small gecko or lizard) you can take in your hands, yet it is found in kings&#8217; (<em>mĕlek</em>, H4428) palaces.&#8221> The smallest and most easily caught creature reaches the highest human institution: the king's palace. The paradox of access: size and power do not determine where one can be found; the lizard's nimbleness takes it where strength cannot.</p>",
    "29": "<p><em>Šĕlōšāh hēmmāh mêṭîbê ṣāʿad</em> = &#8220;Three things are majestic in their stride (<em>ṭôb ṣāʿad</em>); four are stately in their going&#8221; — the fourth four-part series, this time focused on dignity and bearing rather than wisdom or social inversion. <em>Ṭôb ṣāʿad</em> = good/fine of step; the dignity that communicates authority through movement.</p>",
    "30": "<p><em>Lāyiš gibbôr baббĕhēmāh</em> = &#8220;the lion (<em>lāyiš</em>, a rare word for the great/old lion), which is mightiest among beasts and does not turn back before any.&#8221> — <em>lāyiš</em> (only here and Isa 30:6; Job 4:11) is a more intensive lion term than <em>ʾaryēh</em>; the senior or great lion. The lion's dignity is its fearlessness: it does not retreat. The first in the series of stately things.</p>",
    "31": "<p><em>Zarzîr motnayim ʾô-ṭāyiš</em> = &#8220;a strutting rooster or a he-goat (<em>ṭāyiš</em>)&#8221; — the word <em>zarzîr</em> (hapax; possibly &#8220;one girt in the loins&#8221;) is traditionally translated &#8220;strutting rooster&#8221; or &#8220;greyhound&#8221; (LXX) — an animal with visible physical readiness/bearing. <em>Wĕmelek (<em>melek</em>, H4428, dispute_level=2) qûm ʿimmô</em> = &#8220;and a king (<em>melek</em>) with his army arrayed before him.&#8221> The king as the human example of stately bearing — regal authority visible in posture and movement. The series culminates in the king as the human counterpart to the lion.</p>",
    "32": "<p><em>ʾIm-nābaltā bĕhitnaaśēʾ</em> = &#8220;If you have been foolish, exalting yourself (<em>hitnaaśēʾ</em>, lifting yourself up)&#8221; — the return to moral instruction after the observation sections. <em>Wĕʾim-zammôtā yād lĕpeh</em> = &#8220;or if you have devised evil, put your hand over your mouth.&#8221> <em>Yād lĕpeh</em> (hand over the mouth) = the gesture of silencing oneself, stopping before the foolish exaltation or evil device is fully spoken. The gesture is a form of wisdom — catching oneself before words become action.</p>",
    "33": "<p><em>Kî mîṣ ḥālāb yôṣîʾ ḥemʾāh</em> = &#8220;For as pressing (<em>mîṣ</em>) milk produces curds and pressing the nose produces blood, so pressing anger produces strife.&#8221> The concluding proverb of the Agur oracle uses the same physical pressure image three times: the pressing/squeezing that produces inevitable products. Churning milk produces butter; pressing the nose produces blood; pressing anger produces strife. The wisdom application: stop pressing the anger before it produces strife, as you would stop before churning becomes spoilage. The oracle closes with this practical instruction for managing conflict.</p>"
  }
}

def main():
    c = load_comm('mkt-original', 'proverbs')
    merge_comm(c, PROVERBS)
    save_comm('mkt-original', 'proverbs', c)
    total = sum(len(vs) for vs in PROVERBS.values())
    print(f'proverbs mkt-original: {total} entries written (ch28-30)')

if __name__ == '__main__':
    main()
